import logging
import os
import json
from azure.functions import TimerRequest
from azure.storage.blob import BlobServiceClient
from azure.cosmos import CosmosClient
from azure.eventgrid import EventGridPublisherClient
from azure.core.credentials import AzureSasCredential
from azure.identity import DefaultAzureCredential

def main(mytimer: TimerRequest):
    try:
        # Initialize credentials using managed identity
        credential = DefaultAzureCredential()
        
        # Blob Storage configuration
        blob_storage_account_name = os.environ["STORAGE_ACCOUNT_NAME"]
        blob_container_name = os.environ["BLOB_CONTAINER_NAME"]
        
        # Cosmos DB configuration
        cosmos_db_account_endpoint = os.environ["COSMOS_DB_ACCOUNT_ENDPOINT"]
        cosmos_db_account_key = os.environ["COSMOS_DB_ACCOUNT_KEY"]
        cosmos_db_database_name = os.environ["COSMOS_DB_DATABASE_NAME"]
        cosmos_db_container_name = os.environ["COSMOS_DB_CONTAINER_NAME"]
        
        # Event Grid configuration
        event_grid_endpoint = os.environ["EVENT_GRID_ENDPOINT"]
        event_grid_topic_name = os.environ["EVENT_GRID_TOPIC_NAME"]
        
        # Initialize clients
        blob_service_client = BlobServiceClient(
            account_url=f"https://{blob_storage_account_name}.blob.core.windows.net",
            credential=credential
        )
        
        cosmos_client = CosmosClient(
            cosmos_db_account_endpoint,
            cosmos_db_account_key
        )
        
        database = cosmos_client.get_database_client(cosmos_db_database_name)
        container = database.get_container_client(cosmos_db_container_name)
        
        event_grid_client = EventGridPublisherClient(
            endpoint=event_grid_endpoint,
            credential=credential
        )
        
        # List blobs in container
        blob_container_client = blob_service_client.get_container_client(blob_container_name)
        blob_list = blob_container_client.list_blobs()
        
        # Process each blob
        for blob in blob_list:
            try:
                # Download blob content
                blob_client = blob_container_client.get_blob_client(blob.name)
                blob_data = blob_client.download_blob().readall()
                
                # Process data (example: count words)
                processed_data = {
                    "filename": blob.name,
                    "word_count": len(blob_data.decode('utf-8').split()),
                    "processed_at": blob.last_modified.isoformat()
                }
                
                # Write to Cosmos DB
                container.upsert_item(processed_data)
                
                # Send notification via Event Grid
                event_grid_client.send([
                    {
                        "topic": f"/subscriptions/{os.environ['SUBSCRIPTION_ID']}/resourceGroups/{os.environ['RESOURCE_GROUP']}/providers/Microsoft.Storage/storageAccounts/{blob_storage_account_name}",
                        "subject": f"blob_processed/{blob.name}",
                        "eventType": "BlobProcessed",
                        "eventTime": blob.last_modified.isoformat(),
                        "id": str(hash(blob.name)),
                        "data": processed_data
                    }
                ])
                
                logging.info(f"Successfully processed blob: {blob.name}")
                
            except Exception as e:
                logging.error(f"Error processing blob {blob.name}: {str(e)}")
                continue
                
    except Exception as e:
        logging.error(f"Error in main function: {str(e)}")
        raise